import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import './UserProfile.css';

export const UserProfile = ({ onSubscriptionClick, onAdminClick }) => {
  const [showLoginPanel, setShowLoginPanel] = useState(false);

  return (
    <div className="user-profile-container">
      <div className="user-circle" onClick={() => setShowLoginPanel(!showLoginPanel)}>
        <span className="user-initial">U</span>
      </div>

      {showLoginPanel && (
        <>
          <div className="panel-backdrop" onClick={() => setShowLoginPanel(false)}></div>
          <div className="login-panel" onClick={(e) => e.stopPropagation()}>
            <div className="login-content">
              <button className="google-btn">
                <img src="data:image/svg+xml,%3Csvg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 24 24'%3E%3Cpath fill='%234285F4' d='M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z'/%3E%3Cpath fill='%2334A853' d='M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z'/%3E%3Cpath fill='%23FBBC04' d='M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z'/%3E%3Cpath fill='%23E94B3C' d='M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z'/%3E%3C/svg%3E" alt="Google" width="24" height="24" />
                Continue with Google
              </button>
              <p className="disclaimer-text">
                By signing in, you agree to our <a href="#">Terms of Service</a>
                <br />
                and <a href="#">Privacy Policy</a>
              </p>
              <button 
                onClick={() => {
                  onSubscriptionClick();
                  setShowLoginPanel(false);
                }}
                style={{
                  marginTop: '12px',
                  padding: '8px 16px',
                  background: '#FFD700',
                  color: '#000000',
                  border: 'none',
                  borderRadius: '4px',
                  cursor: 'pointer',
                  fontWeight: '600',
                  fontSize: '14px',
                  width: '100%',
                  transition: 'all 0.2s ease',
                }}
                onMouseEnter={(e) => e.target.style.background = '#FFC700'}
                onMouseLeave={(e) => e.target.style.background = '#FFD700'}
              >
                ✨ Upgrade to Premium
              </button>
              <Link 
                to="/admin" 
                className="admin-button-panel"
                title="Go to Admin Dashboard"
                onClick={() => setShowLoginPanel(false)}
              >
                Admin
              </Link>
            </div>
          </div>
        </>
      )}
    </div>
  );
};
